// Script Continued Below
var table = "x_153465_discovert_discover_office_hierarchy";

var records = new GlideRecord(table);
records.addEncodedQuery('active=true'); //KT - STRY0063650
records.query();

// build organization map
var orgMap = {};
var abbrevMap = {};
var nameIter = {};
var abbrevIter = {};
var listOfChangedOrganizations = [];
var listOfChangedAbbrev = [];
while(records.next()) {
	var ouName;
	var num;
	try {
		ouName = records.getValue("office_name");
		// if the office name or abbrev are not valid, skip
		if(!(records.office_name && records.office_abbreviation)) {
			gs.info("Tasker - Flag Org Unit Duplication - Skipping non-valid: " + records.sys_id + " name: " + records.office_name + " abrv: " + records.office_abbreviation);
			continue;
		}
		// gather the lowercase representation of the duplication fix script
		var orgName = records.office_name.toString().toLowerCase();
		var abbrevName = records.office_abbreviation.toString().toLowerCase();
		var trackChange = false;
		//check org name
		if(orgMap[orgName]) {
			num = ++nameIter[orgName];
			var changedName = records.office_name + "-" + num;
			var reportLine = "<li>Changed name " + records.office_name + " to " + changedName+". <a href=\""+ records.getLink()+ "\">Link</a></li>";
			listOfChangedOrganizations.push(reportLine);
			records.office_name = changedName;
			trackChange = true;
		} else {
			orgMap[orgName] = true;
			nameIter[orgName] = 0;
		}

		// -=========================

		//check abbreviation
		if(abbrevMap[abbrevName]) {
			num = ++abbrevIter[abbrevName];
			var changedAbbrev = records.office_abbreviation + "-" + num;
			var abbrevReportLine = "<li>Changed abbrev " + records.office_abbreviation + " to " + changedAbbrev+". <a href=\""+ records.getLink()+ "\">Link</a></li>";
			listOfChangedAbbrev.push(abbrevReportLine);
			records.office_abbreviation = changedAbbrev;
			trackChange = true;
		} else {
			abbrevMap[abbrevName] = true;
			abbrevIter[abbrevName] = 0;
		}
		//if anything changed, update
		if(trackChange) {
			records.update();
		}
	} catch(e) {
		gs.error("OU Name:" + ouName + " - Error in 'Flag Org Unit Duplication' - exception: " + e);
	}			
}

try {
	var header = "<img src=\"tasker_logo.pngx\" width=\"100\" height=\"20\"/><br/><h2>OU Hierarchy Duplicate Fix Script Report</h2>";
	//report on name changes
	if(listOfChangedOrganizations.length > 0 || listOfChangedAbbrev.length > 0) {
		var finalReport = header + "<h3>Name Changes</h3><ul>";
		for(var i=0; i < listOfChangedOrganizations.length; i++) {
			finalReport = [finalReport, listOfChangedOrganizations[i]].join("");
		}
		finalReport += "</ul><h3>Abbreviation Changes</h3><ul>";
		for(var j=0; j < listOfChangedAbbrev.length; j++) {
			finalReport = [finalReport, listOfChangedAbbrev[j]].join("");
		}
		finalReport += "</ul>";
		gs.eventQueue("x_153465_discovert.GenericFixScriptEmail",null,gs.getUserID(),finalReport);
	} else {
		gs.eventQueue("x_153465_discovert.GenericFixScriptEmail",null,gs.getUserID(),header + "<p>All records are unique and no changes were made<p>");
	}
} catch(e) {
	gs.error("Error in 'Flag Org Unit Duplication' - Sending email listing exceptions - exception: " + e);
}
